+/// Round `size` up to the next multiple of `SEGMENT_ALIGNMENT` (64).
+fn align_up(size: usize) -> usize {
+    (size + SEGMENT_ALIGNMENT - 1) & !(SEGMENT_ALIGNMENT - 1)
+}
