+        let phase = make_static_phase();
+        vitals = detector.process_frame(&amp, &phase);
+    }
+
+    if let Some(bpm) = vitals.breathing_rate_bpm {
+        assert!(
+            bpm >= 6.0 && bpm <= 30.0,
+            "breathing rate {:.1} BPM must be in range [6, 30]",
+            bpm
+        );
+    }
+}
